```javascript
'use strict';

/**
 * Sliding window rate limiting middleware for Express.
 *
 * This is a TRUE sliding window: every request's timestamp is recorded, and on
 * each request we drop timestamps older than `windowMs` before counting. There
 * is no fixed interval that resets the counter to zero, so a client cannot
 * "burst" across a window boundary the way they can with fixed-window limiters.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]   Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]  Max requests allowed per window.
 * @returns {Function} Express middleware with an attached `.close()` method.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;

  // Map<clientIp, number[]>  — sorted-ascending arrays of request timestamps (ms).
  const hits = new Map();

  /**
   * Remove timestamps that fall outside the sliding window.
   * Timestamps are appended in chronological order, so the valid entries are
   * always a contiguous suffix — we find the first index >= cutoff and slice.
   */
  function prune(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i > 0 ? timestamps.slice(i) : timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;

    // NOTE ON req.ip BEHIND PROXIES:
    // Express derives `req.ip` from the socket address by default, so behind a
    // reverse proxy/load balancer (Nginx, ELB, Cloudflare) every request looks
    // like it comes from the proxy's IP and all clients share one bucket.
    // Enable proxy trust on the app so Express reads the leftmost untrusted
    // X-Forwarded-For entry instead:
    //     app.set('trust proxy', 1)            // trust one proxy hop
    //     app.set('trust proxy', 'loopback')   // or a specific subnet/list
    // Only trust proxies you actually control — clients can spoof
    // X-Forwarded-For otherwise, letting them evade or poison the limiter.
    const key = req.ip || req.socket?.remoteAddress || 'unknown';

    const pruned = prune(hits.get(key) || [], cutoff);

    if (pruned.length >= maxRequests) {
      // Over the limit: the window frees up when the OLDEST in-window request
      // ages out (oldest timestamp + windowMs).
      const oldest = pruned[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned list so we don't leak stale timestamps.
      hits.set(key, pruned);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      return res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // Under the limit: record this request and allow it.
    pruned.push(now);
    hits.set(key, pruned);

    const remaining = Math.max(0, maxRequests - pruned.length);
    // The window resets (a slot frees) when the oldest in-window request expires.
    const resetMs = pruned[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    return next();
  };

  // ---- Memory management -------------------------------------------------
  // Periodically drop IP buckets that have no requests inside the window so the
  // Map doesn't grow unbounded from one-off clients.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const pruned = prune(timestamps, cutoff);
      if (pruned.length === 0) {
        hits.delete(key);
      } else if (pruned.length !== timestamps.length) {
        hits.set(key, pruned);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupInterval.unref === 'function') {
    cleanupInterval.unref();
  }

  /** Stop the cleanup timer (call on shutdown / in tests). */
  middleware.close = function close() {
    clearInterval(cleanupInterval);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

## Usage

```javascript
const express = require('express');
const createRateLimiter = require('./rate-limiter');

const app = express();

// IMPORTANT behind Nginx/ELB/Cloudflare: otherwise req.ip is the proxy IP
// and all clients share a single bucket.
app.set('trust proxy', 1);

// 100 requests per 60s per IP (the defaults).
const limiter = createRateLimiter({ windowMs: 60000, maxRequests: 100 });

// Apply globally...
app.use(limiter);

// ...or to a specific route group:
// app.use('/api/', limiter);

app.get('/', (req, res) => res.send('ok'));

const server = app.listen(3000);

// Clean shutdown stops the cleanup timer.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
```

## Why this is a true sliding window

- Every request stores its own timestamp; counting is done over `[now - windowMs, now]` on **each** request.
- There is no shared "reset at the top of the minute" clock, so a client can't fire `maxRequests` at `0:59` and another `maxRequests` at `1:00`. The limit is enforced continuously against the trailing `windowMs`.
- `X-RateLimit-Reset` / `Retry-After` are computed from the **oldest in-window timestamp expiring** (`oldest + windowMs`), which is the exact moment a slot frees up — not a fixed boundary.

A couple of operational notes:

- **Single-process only.** State lives in an in-memory `Map`, so it doesn't share counts across clustered/multi-instance deployments. For that, back the timestamps with Redis (e.g. a sorted set per IP with `ZREMRANGEBYSCORE` for pruning and `ZCARD` for the count — same algorithm, shared store).
- **Memory is bounded** by active IPs × requests-in-window, with the 60s sweep reclaiming idle buckets; `unref()` plus `close()` ensure the timer never keeps the process alive.

