/**
 * Creates an Express rate-limiting middleware using a true sliding window.
 *
 * @param {object}  [options]
 * @param {number}  [options.windowMs=60000]   - Window length in milliseconds.
 * @param {number}  [options.maxRequests=100]  - Max requests allowed per window.
 * @returns {{ middleware: Function, close: Function }}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;

  // Map<ip: string, timestamps: number[]>
  // Each entry holds the hit timestamps (epoch ms) still within the window.
  const store = new Map();

  // ── Periodic cleanup ────────────────────────────────────────────────────────
  // Removes store entries for IPs whose last request falls outside the window.
  // Without this, every IP that ever made a request would stay in memory forever.
  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    for (const [ip, timestamps] of store.entries()) {
      // Keep only timestamps still inside the window.
      const alive = timestamps.filter(ts => now - ts < windowMs);
      if (alive.length === 0) {
        store.delete(ip);   // IP has no recent activity — free the entry.
      } else {
        store.set(ip, alive);
      }
    }
  }, 60_000); // run every 60 s

  // Prevent the interval from keeping the Node.js event loop alive when the
  // consuming application shuts down (e.g. in tests or graceful shutdowns).
  cleanupInterval.unref();

  // ── Middleware ───────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const now = Date.now();
    const ip  = req.ip ?? req.socket?.remoteAddress ?? 'unknown';

    // 1. Fetch existing timestamps for this IP (default to empty array).
    let timestamps = store.get(ip) ?? [];

    // 2. Evict timestamps that have slid out of the current window.
    //    This is the core of the sliding window: we don't reset on a schedule;
    //    we recompute the valid window on every single request.
    const windowStart = now - windowMs;
    timestamps = timestamps.filter(ts => ts > windowStart);

    // 3. Decide: allow or reject.
    if (timestamps.length >= maxRequests) {
      // ── Rejected ────────────────────────────────────────────────────────────
      // The oldest timestamp still in the window tells us the earliest moment
      // at which one slot will free up (oldest + windowMs).
      const oldestTs    = timestamps[0];            // array is insertion-ordered ∴ ascending
