    //    Reset = the moment the *oldest* timestamp in the updated window expires,
    //    i.e. when at least one additional slot will become available.
    const remaining = maxRequests - timestamps.length;
    const resetMs   = timestamps.length > 0
      ? timestamps[0] + windowMs   // epoch ms when the oldest slot frees
      : now + windowMs;
    const resetS    = Math.ceil(resetMs / 1000);  // epoch seconds for the header

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(remaining),
      'X-RateLimit-Reset':     String(resetS),
    });

